<tr><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Downtown Dubai</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;text-align:center;">~30 min</td></tr>
<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Dubai Marina</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;text-align:center;">~35 min</td></tr>
