<table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:14px;"><thead><tr style="background:#1e3a5f;color:#fff;"><th style="padding:10px;text-align:left;">Karat</th><th style="padding:10px;">Purity</th><th style="padding:10px;">Best For</th><th style="padding:10px;">Price Level</th></tr></thead><tbody>
