<tr><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>22K</strong></td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">91.6%</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Indian bridal &amp; traditional</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">High</td></tr>
