<h2>Key Attractions</h2>
<table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:14px;"><thead><tr style="background:#1e3a5f;color:#fff;"><th style="padding:10px;text-align:left;">Attraction</th><th style="padding:10px;">Entry Fee</th><th style="padding:10px;">Duration</th><th style="padding:10px;">Highlight</th></tr></thead><tbody>
