<tr><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>XVA Gallery &amp; Cafe</strong></td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Free gallery</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">45–60 min</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Restored courtyard art space</td></tr>
